// // Selects the source operand based on ForwardAE; outputs RD1_out when ForwardAE is 00, ResultW when 01, and ALUOutM when 10
module top_module(
   input [31:0]RD1_out,
	input [31:0]ALUOutM,
	input [31:0]ResultW,
   input [1:0]ForwardAE,
	output [31:0]SrcAE
);assign SrcAE = (ForwardAE==2'd0)?RD1_out:(ForwardAE==2'd1)?ResultW:ALUOutM;
endmodule
